const KB_MAP = {
  'eilinaire_constitution.md':  'KB-01',
  'peabuntid_constitution.md':  'KB-01',
  'ego_era_bible.md':           'KB-02',
  'trading/rules.md':           'KB-03',
  'job/dept_marketing.md':      'KB-04',
  'job/dept_ops.md':            'KB-04',
  'Decision_Memory_Log':        'KB-05'
};

const body = $input.first().json;
// Support both webhook (file change) and manual trigger
const sourceFile = body.source_file || body.name || body.file || '';
const content    = body.content    || body.text  || '';

const kbId = Object.entries(KB_MAP).find(([k]) => sourceFile.includes(k))?.[1] || null;

if (!kbId) throw new Error('No KB mapping found for: ' + sourceFile);

return [{ json: { kb_id: kbId, source_file: sourceFile, content, triggered_at: new Date().toISOString() } }];

